1	/**
2	 * ingest-ripple.ts — 漣漪式 Wiki 更新
3	 *
4	 * 當新 fact 寫入（remember）時，檢查是否有相關 wiki page 需要更新。
5	 * 設計原則：
6	 * - fire-and-forget，不阻塞 remember 主路徑
7	 * - 不直接改 wiki 頁面（那是 agent 的工作），只產出「待更新」標記
8	 * - 標記累積到門檻後，由 /dream 或 /wikisync 一次性處理
9	 *
10	 * 機制：
11	 * 1. 新 fact 寫入 → 取出 topic → 找到對應 wiki page
12	 * 2. 比對 wiki page 的 sources frontmatter → 算出「新增 facts 數」
13	 * 3. 新增 facts ≥ RIPPLE_THRESHOLD → 追加到 wiki-ripple.jsonl
14	 * 4. /dream 的 wikisync 步驟可讀取 ripple log 決定優先更新哪些頁面
15	 */
16	
17	import { readFileSync, existsSync, appendFileSync, writeFileSync, mkdirSync } from "node:fs";
18	import path from "node:path";
19	import { config } from "./config.js";
20	
21	// ─── 常數 ─────────────────────────────────────────────────────────────────
22	
23	/** 累積多少新 fact 才標記為需更新 */
24	const RIPPLE_THRESHOLD = 3;
25	
26	/** ripple log 最大筆數（防無界增長） */
27	const MAX_RIPPLE_ENTRIES = 200;
28	
29	/** wiki index 路徑 */
30	const WIKI_INDEX_PATH = path.join(config.memoryDir, "wiki", "index.md");
31	
32	/** ripple log 路徑 */
33	const RIPPLE_LOG_PATH = path.join(config.memoryDir, "wiki", "wiki-ripple.jsonl");
34	
35	// ─── 型別 ─────────────────────────────────────────────────────────────────
36	
37	export interface RippleEntry {
38	  /** ISO timestamp */
39	  ts: string;
40	  /** 觸發此 ripple 的 topic */
41	  topic: string;
42	  /** 對應的 wiki slug（如果有） */
43	  wikiSlug: string | null;
44	  /** wiki page 的 type（concepts / lessons / references） */
45	  wikiType: string | null;
46	  /** 觸發的 fact 文字（截斷） */
47	  factPreview: string;
48	  /** 該 page 目前累積的未同步 fact 數 */
49	  pendingCount: number;
50	  /** 是否達到更新門檻 */
51	  thresholdReached: boolean;
52	}
53	
54	export interface RippleStatus {
55	  /** 需要更新的 wiki page（已達門檻） */
56	  pagesNeedingUpdate: Array<{
57	    slug: string;
58	    type: string;
59	    topic: string;
60	    pendingCount: number;
61	    lastRipple: string;
62	  }>;
63	  /** 尚未達門檻的 page */
64	  pagesWatching: Array<{
65	    slug: string;
66	    type: string;
67	    topic: string;
68	    pendingCount: number;
69	  }>;
70	}
71	
72	// ─── 內部工具 ─────────────────────────────────────────────────────────────
73	
74	/** 解析 wiki/index.md，取得 slug → topic 映射 */
75	function parseWikiIndex(): Map<string, { slug: string; type: string }> {
76	  const map = new Map<string, { slug: string; type: string }>();
77	  if (!existsSync(WIKI_INDEX_PATH)) return map;
78	
79	  try {
80	    const content = readFileSync(WIKI_INDEX_PATH, "utf8");
81	    // 格式：- [[slug]] — 描述
82	    const re = /^-\s*\[\[([^\]]+)\]\]\s*—\s*(.+)$/gm;
83	    let m: RegExpExecArray | null;
84	    let currentType = "concepts";
85	
86	    for (const line of content.split(/\r?\n/)) {
87	      // 偵測 section 標題
88	      if (/^##\s*Pages/i.test(line)) currentType = "concepts";
89	      else if (/^##\s*Lessons/i.test(line)) currentType = "lessons";
90	      else if (/^##\s*References/i.test(line)) currentType = "references";
91	      else if (/^##\s*Tasks/i.test(line)) currentType = "tasks";
92	      else if (/^##\s*Queries/i.test(line)) currentType = "queries";
93	
94	      re.lastIndex = 0;
95	      m = re.exec(line);
96	      if (m) {
97	        const slug = m[1];
98	        // slug 通常就是 topic 名（kebab-case）
99	        map.set(slug, { slug, type: currentType });
100	      }
101	    }
102	  } catch { /* 讀取失敗，回傳空 map */ }
103	  return map;
104	}
105	
106	/** 讀取 wiki page 的 sources frontmatter（fact IDs 列表） */
107	function getPageSources(slug: string, type: string): Set<string> {
108	  const sources = new Set<string>();
109	  const pagePath = path.join(config.memoryDir, "wiki", type, `${slug}.md`);
110	  if (!existsSync(pagePath)) return sources;
111	
112	  try {
113	    const content = readFileSync(pagePath, "utf8");
114	    // frontmatter: sources: [f_xxxxxx, f_yyyyyy, ...]
115	    const match = content.match(/^sources:\s*\[([^\]]*)\]/m);
116	    if (match) {
117	      const ids = match[1].split(",").map((s) => s.trim()).filter(Boolean);
118	      for (const id of ids) sources.add(id);
119	    }
120	  } catch { /* 讀取失敗 */ }
121	  return sources;
122	}
123	
124	/** 讀取 topic shard 的 fact IDs */
125	function getShardFactIds(topic: string): string[] {
126	  const userId = getActiveUserId();
127	  if (!userId) return [];
128	
129	  // topic → filename：kebab-case 對應
130	  const shardDir = path.join(config.memoryDir, `facts_Topic`, String(userId));
131	  if (!existsSync(shardDir)) return [];
132	
133	  // 找到對應 shard 檔案
134	  const candidates = [
135	    path.join(shardDir, `${topic}.md`),
136	    path.join(shardDir, `${topic.replace(/-/g, "_")}.md`),
137	  ];
138	
139	  for (const filePath of candidates) {
140	    if (!existsSync(filePath)) continue;
141	    try {
142	      const content = readFileSync(filePath, "utf8");
143	      const ids: string[] = [];
144	      for (const line of content.split(/\r?\n/)) {
145	        const m = line.match(/\[f_([0-9a-f]{6})\]/);
146	        if (m) ids.push(`f_${m[1]}`);
147	      }
148	      return ids;
149	    } catch { /* 忽略 */ }
150	  }
151	  return [];
152	}
153	
154	function getActiveUserId(): number | null {
155	  const raw = (process.env.TG_ACTIVE_USER_ID ?? "").trim() ||
156	    (process.env.MEMORY_USER_ID ?? "").trim();
157	  if (raw) {
158	    const n = Number(raw);
159	    if (Number.isFinite(n) && n > 0) return n;
160	  }
161	  try {
162	    const filePath = path.join(config.memoryDir, ".user-id");
163	    const content = readFileSync(filePath, "utf8").trim();
164	    const n = Number(content);
165	    if (Number.isFinite(n) && n > 0) return n;
166	  } catch { /* 忽略 */ }
167	  return null;
168	}
169	
170	// ─── 公開 API ─────────────────────────────────────────────────────────────
171	
172	/**
173	 * 新 fact 寫入時呼叫。fire-and-forget，不拋錯。
174	 * @param topic - 該 fact 被分類到的 topic
175	 * @param factText - fact 原文（用於 preview）
176	 * @param factId - fact ID（如 f_abc123）
177	 */
178	export function onFactIngested(topic: string, factText: string, factId?: string): void {
179	  try {
180	    const wikiIndex = parseWikiIndex();
181	
182	    // 找到對應的 wiki page（topic slug = wiki slug）
183	    const wikiEntry = wikiIndex.get(topic);
184	    const wikiSlug = wikiEntry?.slug ?? null;
185	    const wikiType = wikiEntry?.type ?? null;
186	
187	    // 計算 pending count
188	    let pendingCount = 1;
189	    if (wikiSlug && wikiType) {
190	      const pageSources = getPageSources(wikiSlug, wikiType);
191	      const shardIds = getShardFactIds(topic);
192	      // 未被 wiki page 追蹤的 fact 數
193	      pendingCount = shardIds.filter((id) => !pageSources.has(id)).length;
194	    }
195	
196	    const entry: RippleEntry = {
197	      ts: new Date().toISOString(),
198	      topic,
199	      wikiSlug,
200	      wikiType,
201	      factPreview: factText.slice(0, 100),
202	      pendingCount,
203	      thresholdReached: pendingCount >= RIPPLE_THRESHOLD,
204	    };
205	
206	    // 寫入 ripple log
207	    const dir = path.dirname(RIPPLE_LOG_PATH);
208	    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
209	    appendFileSync(RIPPLE_LOG_PATH, JSON.stringify(entry) + "\n", "utf8");
210	
211	    // 體積控制：超過上限時截斷
212	    trimRippleLog();
213	  } catch (err) {
214	    // ripple 是旁路訊號，絕不影響主路徑
215	    console.error("[ingest-ripple] failed:", err);
216	  }
217	}
218	
219	/**
220	 * 取得目前的 ripple 狀態（供 /dream wikisync 步驟讀取）。
221	 */
222	export function getRippleStatus(): RippleStatus {
223	  const status: RippleStatus = {
224	    pagesNeedingUpdate: [],
225	    pagesWatching: [],
226	  };
227	
228	  if (!existsSync(RIPPLE_LOG_PATH)) return status;
229	
230	  try {
231	    const content = readFileSync(RIPPLE_LOG_PATH, "utf8");
232	    const lines = content.trim().split("\n").filter(Boolean);
233	
234	    // 聚合：per-topic 取最新一筆
235	    const latestByTopic = new Map<string, RippleEntry>();
236	    for (const line of lines) {
237	      try {
238	        const entry: RippleEntry = JSON.parse(line);
239	        const existing = latestByTopic.get(entry.topic);
240	        if (!existing || entry.ts > existing.ts) {
241	          latestByTopic.set(entry.topic, entry);
242	        }
243	      } catch { /* 跳過 */ }
244	    }
245	
246	    for (const entry of latestByTopic.values()) {
247	      if (!entry.wikiSlug) continue; // 沒有對應 wiki page 的跳過
248	
249	      if (entry.thresholdReached) {
250	        status.pagesNeedingUpdate.push({
251	          slug: entry.wikiSlug,
252	          type: entry.wikiType!,
253	          topic: entry.topic,
254	          pendingCount: entry.pendingCount,
255	          lastRipple: entry.ts,
256	        });
257	      } else {
258	        status.pagesWatching.push({
259	          slug: entry.wikiSlug,
260	          type: entry.wikiType!,
261	          topic: entry.topic,
262	          pendingCount: entry.pendingCount,
263	        });
264	      }
265	    }
266	
267	    // 按 pendingCount 降序
268	    status.pagesNeedingUpdate.sort((a, b) => b.pendingCount - a.pendingCount);
269	  } catch { /* 讀取失敗 */ }
270	
271	  return status;
272	}
273	
274	/**
275	 * 清除已處理的 ripple 記錄（wikisync 完成後呼叫）。
276	 * @param processedTopics - 已成功更新的 topic 列表
277	 */
278	export function clearProcessedRipples(processedTopics: string[]): void {
279	  if (!existsSync(RIPPLE_LOG_PATH)) return;
280	
281	  try {
282	    const content = readFileSync(RIPPLE_LOG_PATH, "utf8");
283	    const lines = content.trim().split("\n").filter(Boolean);
284	    const topicSet = new Set(processedTopics);
285	
286	    const remaining = lines.filter((line) => {
287	      try {
288	        const entry: RippleEntry = JSON.parse(line);
289	        return !topicSet.has(entry.topic);
290	      } catch { return true; }
291	    });
292	
293	    writeFileSync(RIPPLE_LOG_PATH, remaining.join("\n") + (remaining.length ? "\n" : ""), "utf8");
294	  } catch (err) {
295	    console.error("[ingest-ripple] clearProcessedRipples failed:", err);
296	  }
297	}
298	
299	/** 體積控制：保留最後 MAX_RIPPLE_ENTRIES 筆 */
300	function trimRippleLog(): void {
301	  try {
302	    const content = readFileSync(RIPPLE_LOG_PATH, "utf8");
303	    const lines = content.trim().split("\n").filter(Boolean);
304	    if (lines.length <= MAX_RIPPLE_ENTRIES) return;
305	
306	    const trimmed = lines.slice(-MAX_RIPPLE_ENTRIES);
307	    writeFileSync(RIPPLE_LOG_PATH, trimmed.join("\n") + "\n", "utf8");
308	  } catch { /* 忽略 */ }
309	}
