/**
 * activity-log.ts — Unified Activity Log
 *
 * 提供統一讀取介面，把三個獨立 JSONL log（hit-log、event-log、tool-observer）
 * 合併為單一時序活動流。不改各自的寫入邏輯（向後相容），只在讀取端統一。
 *
 * 用途：
 * - /dream 產出每日活動摘要
 * - 未來 instinct observer 分析
 * - wiki 更新觸發判斷（Ingest Ripple 消費此流）
 */

import { readFileSync, existsSync } from "node:fs";
import path from "node:path";
import { config } from "./config.js";
import type { HitEntry } from "./hit-log.js";
import type { StateEvent } from "./event-log.js";
import type { Observation } from "./tool-observer.js";

// ─── 統一 Schema ──────────────────────────────────────────────────────────

export type ActivitySource = "hit" | "event" | "observation";

export interface ActivityEntry {
  /** ISO timestamp */
  ts: string;
  /** 來源 log 系統 */
  source: ActivitySource;
  /** 活動類別（hit type / event type / tool name） */
  category: string;
  /** 一行摘要（人類可讀） */
  summary: string;
  /** 原始資料（完整保留供消費者深入分析） */
  raw: HitEntry | StateEvent | Observation;
}

// ─── Log 路徑 ─────────────────────────────────────────────────────────────

const HIT_LOG_PATH = path.join(config.memoryDir, "hit-log.jsonl");
const EVENT_LOG_PATH = path.join(config.memoryDir, "events.jsonl");
const OBSERVATIONS_PATH = path.join(config.memoryDir, "observations.jsonl");

// ─── 解析器 ──────────────────────────────────────────────────────────────

function parseHitEntries(since: string): ActivityEntry[] {
  if (!existsSync(HIT_LOG_PATH)) return [];
  const entries: ActivityEntry[] = [];
  try {
    const raw = readFileSync(HIT_LOG_PATH, "utf8");
    for (const line of raw.split("\n")) {
      if (!line.trim()) continue;
      try {
        const e: HitEntry = JSON.parse(line);
        if (e.ts < since) continue;
        entries.push({
          ts: e.ts,
          source: "hit",
          category: e.type,
          summary: `${e.type} 命中: ${e.key} (from ${e.source})`,
          raw: e,
        });
      } catch { /* 跳過格式錯誤行 */ }
    }
  } catch { /* 檔案讀取失敗 */ }
  return entries;
}

function parseEventEntries(since: string): ActivityEntry[] {
  if (!existsSync(EVENT_LOG_PATH)) return [];
  const entries: ActivityEntry[] = [];
  try {
    const raw = readFileSync(EVENT_LOG_PATH, "utf8");
    for (const line of raw.split("\n")) {
      if (!line.trim()) continue;
      try {
        const e: StateEvent = JSON.parse(line);
        if (e.ts < since) continue;
        const detail = summarizeEvent(e);
        entries.push({
          ts: e.ts,
          source: "event",
          category: e.type,
          summary: detail,
          raw: e,
        });
      } catch { /* 跳過格式錯誤行 */ }
    }
  } catch { /* 檔案讀取失敗 */ }
  return entries;
}

function parseObservationEntries(since: string): ActivityEntry[] {
  if (!existsSync(OBSERVATIONS_PATH)) return [];
  const entries: ActivityEntry[] = [];
  try {
    const raw = readFileSync(OBSERVATIONS_PATH, "utf8");
    for (const line of raw.split("\n")) {
      if (!line.trim()) continue;
      try {
        const e: Observation = JSON.parse(line);
        if (e.ts < since) continue;
        const status = e.status ? ` [${e.status}]` : e.isError ? " [error]" : "";
        entries.push({
          ts: e.ts,
          source: "observation",
          category: e.name,
          summary: `tool: ${e.name}${status}`,
          raw: e,
        });
      } catch { /* 跳過格式錯誤行 */ }
    }
  } catch { /* 檔案讀取失敗 */ }
  return entries;
}

function summarizeEvent(e: StateEvent): string {
  const p = e.payload;
  switch (e.type) {
    case "session_start": return `session 開始${p.sessionId ? ` (${String(p.sessionId).slice(0, 8)})` : ""}`;
    case "session_end": return `session 結束${p.reason ? `: ${p.reason}` : ""}`;
    case "goal_start": return `goal 啟動: ${p.objective ?? ""}`;
    case "goal_done": return `goal 完成: ${p.reason ?? ""}`;
    case "goal_cancel": return `goal 取消`;
    case "specialist_spawn": return `specialist 啟動: ${p.name ?? ""}`;
    case "specialist_done": return `specialist 完成: ${p.name ?? ""}`;
    case "scheduler_fire": return `排程觸發: ${p.prompt ?? p.id ?? ""}`;
    case "tool_call": return `tool call: ${p.name ?? ""}${p.status === "failed" ? " [failed]" : ""}`;
    case "error": return `錯誤: ${p.message ?? p.error ?? ""}`;
    default: return `${e.type}`;
  }
}

// ─── 公開 API ─────────────────────────────────────────────────────────────

export interface ActivityQueryOptions {
  /** 起始時間（ISO string），預設 24 小時前 */
  since?: string;
  /** 過濾來源 */
  sources?: ActivitySource[];
  /** 過濾類別（支援前綴匹配） */
  categories?: string[];
  /** 最多回傳筆數 */
  limit?: number;
}

/**
 * 查詢統一活動流。合併三個 log 並依時序排序。
 */
export function queryActivity(opts: ActivityQueryOptions = {}): ActivityEntry[] {
  const since = opts.since ?? new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
  const sources = opts.sources ?? ["hit", "event", "observation"];
  const limit = opts.limit ?? 500;

  let entries: ActivityEntry[] = [];

  if (sources.includes("hit")) entries.push(...parseHitEntries(since));
  if (sources.includes("event")) entries.push(...parseEventEntries(since));
  if (sources.includes("observation")) entries.push(...parseObservationEntries(since));

  // 類別過濾
  if (opts.categories?.length) {
    entries = entries.filter((e) =>
      opts.categories!.some((c) => e.category.startsWith(c))
    );
  }

  // 依時序排序（新→舊）
  entries.sort((a, b) => b.ts.localeCompare(a.ts));

  return entries.slice(0, limit);
}

/**
 * 取得活動摘要統計（用於 /dream 報告或 Ingest Ripple 判斷）。
 */
export function getActivitySummary(hours = 24): {
  total: number;
  bySource: Record<ActivitySource, number>;
  topCategories: Array<{ category: string; count: number }>;
  factHits: number;
  wikiHits: number;
} {
  const since = new Date(Date.now() - hours * 60 * 60 * 1000).toISOString();
  const entries = queryActivity({ since });

  const bySource: Record<ActivitySource, number> = { hit: 0, event: 0, observation: 0 };
  const catMap = new Map<string, number>();
  let factHits = 0;
  let wikiHits = 0;

  for (const e of entries) {
    bySource[e.source]++;
    catMap.set(e.category, (catMap.get(e.category) ?? 0) + 1);
    if (e.source === "hit") {
      const hitRaw = e.raw as HitEntry;
      if (hitRaw.type === "fact") factHits++;
      if (hitRaw.type === "wiki") wikiHits++;
    }
  }

  const topCategories = [...catMap.entries()]
    .map(([category, count]) => ({ category, count }))
    .sort((a, b) => b.count - a.count)
    .slice(0, 10);

  return { total: entries.length, bySource, topCategories, factHits, wikiHits };
}

