1	/**
2	 * query-auto-save.ts — 自動偵測優質回覆並儲存為 Wiki Query page
3	 *
4	 * 補強 <<WIKI_QUERY:slug|summary>> token 的覆蓋率。Agent 不一定每次都記得
5	 * 加 token，這個模組在回覆完成後自動評估是否值得存入 wiki。
6	 *
7	 * 觸發條件（全部滿足）：
8	 * 1. 回覆長度 ≥ MIN_REPLY_LENGTH（200 字）
9	 * 2. agent 未自行加 WIKI_QUERY token
10	 * 3. 不是 meta / continuation / relay 等非使用者直接提問的回合
11	 * 4. 回覆涉及 ≥ MIN_TOPIC_DIVERSITY 個不同 topic
12	 * 5. 同一 slug 不重複儲存（dedup）
13	 *
14	 * 設計：
15	 * - 不直接觸發 wiki 寫入（那是 agent 的工作）
16	 * - 產出候選清單到 wiki-auto-save-candidates.jsonl
17	 * - /dream wikisync 步驟讀取候選清單，由 agent 一次性處理
18	 * - 可選：即時觸發 meta prompt（同 WIKI_QUERY 機制，由呼叫端決定）
19	 */
20	
21	import { readFileSync, existsSync, appendFileSync, mkdirSync, writeFileSync } from "node:fs";
22	import path from "node:path";
23	import { config } from "./config.js";
24	
25	// ─── 常數 ─────────────────────────────────────────────────────────────────
26	
27	/** 回覆最低字數（含 CJK） */
