/**
 * query-auto-save.ts — 自動偵測優質回覆並儲存為 Wiki Query page
 *
 * 補強 <<WIKI_QUERY:slug|summary>> token 的覆蓋率。Agent 不一定每次都記得
 * 加 token，這個模組在回覆完成後自動評估是否值得存入 wiki。
 *
 * 觸發條件（全部滿足）：
 * 1. 回覆長度 ≥ MIN_REPLY_LENGTH（200 字）
 * 2. agent 未自行加 WIKI_QUERY token
 * 3. 不是 meta / continuation / relay 等非使用者直接提問的回合
 * 4. 回覆涉及 ≥ MIN_TOPIC_DIVERSITY 個不同 topic
 * 5. 同一 slug 不重複儲存（dedup）
 *
 * 設計：
 * - 不直接觸發 wiki 寫入（那是 agent 的工作）
 * - 產出候選清單到 wiki-auto-save-candidates.jsonl
 * - /dream wikisync 步驟讀取候選清單，由 agent 一次性處理
 * - 可選：即時觸發 meta prompt（同 WIKI_QUERY 機制，由呼叫端決定）
 */

import { readFileSync, existsSync, appendFileSync, mkdirSync, writeFileSync } from "node:fs";
import path from "node:path";
import { config } from "./config.js";

// ─── 常數 ─────────────────────────────────────────────────────────────────

/** 回覆最低字數（含 CJK） */
const MIN_REPLY_LENGTH = 200;

/** 最少涉及幾個不同 topic 才算「綜合性回覆」 */
const MIN_TOPIC_DIVERSITY = 3;

/** 候選 log 最大筆數 */
const MAX_CANDIDATES = 100;

/** slug 最大長度 */
const MAX_SLUG_LENGTH = 80;

/** 候選 log 路徑 */
const CANDIDATES_PATH = path.join(config.memoryDir, "wiki", "wiki-auto-save-candidates.jsonl");

/** 既有 wiki queries 目錄 */
const WIKI_QUERIES_DIR = path.join(config.memoryDir, "wiki", "queries");

// ─── 型別 ─────────────────────────────────────────────────────────────────

export interface AutoSaveCandidate {
  /** ISO timestamp */
  ts: string;
  /** 建議的 wiki slug */
  slug: string;
  /** 自動產出的摘要（≤200 字） */
  summary: string;
  /** 匹配到的 topics */
  matchedTopics: string[];
  /** 回覆長度 */
  replyLength: number;
  /** 使用者原始問題（截斷） */
  questionPreview: string;
  /** 是否已被處理 */
  processed: boolean;
}

export interface AutoSaveEvalResult {
  /** 是否值得儲存 */
  shouldSave: boolean;
  /** 建議的 slug */
  slug: string | null;
  /** 建議的 summary */
  summary: string | null;
  /** 匹配到的 topics */
  matchedTopics: string[];
  /** 跳過原因（如果不儲存） */
  skipReason: string | null;
}

// ─── 內部工具 ─────────────────────────────────────────────────────────────

/** 載入 topics.json 的 topic 名稱列表 */
function loadTopicNames(): string[] {
  const topicsPath = path.join(config.memoryDir, "topics.json");
  if (!existsSync(topicsPath)) return [];
  try {
    const raw = JSON.parse(readFileSync(topicsPath, "utf8"));
    if (Array.isArray(raw)) {
      return raw.map((t: { name?: string }) => t.name ?? "").filter(Boolean);
    }
    return [];
  } catch { return []; }
}

/** 偵測回覆中涉及哪些 topic（簡易 keyword 匹配） */
function detectTopics(text: string, topicNames: string[]): string[] {
  const lower = text.toLowerCase();
  const matched: string[] = [];
  for (const topic of topicNames) {
    // topic 名是 kebab-case，轉成可搜尋的關鍵字
    const keywords = topic.split("-").filter((w) => w.length >= 2);
    // 至少一個關鍵字出現在文中
    if (keywords.some((kw) => lower.includes(kw))) {
      matched.push(topic);
    }
  }
  return matched;
}

/** 從使用者問題和回覆內容產出 slug */
function generateSlug(question: string): string {
  // 取問題的前幾個有意義的詞做 slug
  const cleaned = question
    .replace(/[^\w\u4e00-\u9fff\s-]/g, "") // 保留中英文字母數字連字號
    .trim()
    .slice(0, 60);

  let slug = cleaned
    .toLowerCase()
    .replace(/[\s\u4e00-\u9fff]+/g, (match) => {
      // 中文直接用 pinyin 替代不實際，改用短 hash
      if (/[\u4e00-\u9fff]/.test(match)) return "-";
      return "-";
    })
    .replace(/[^a-z0-9-]/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");

  // 如果 slug 太短或全是 dash（中文問題），加時間戳
  if (slug.length < 3) {
    slug = `query-${Date.now().toString(36)}`;
  }

  return slug.slice(0, MAX_SLUG_LENGTH);
}

/** 產出摘要（取回覆前 200 字做簡化） */
function generateSummary(question: string, replyText: string): string {
  // 優先用問題作為摘要
  const q = question.trim().slice(0, 180);
  if (q.length >= 10) return q;
  // fallback：回覆第一段
  const firstParagraph = replyText.split(/\n\n/)[0]?.trim() ?? "";
  return firstParagraph.slice(0, 180) || "自動儲存的綜合性回覆";
}

/** 檢查 slug 是否已存在（dedup） */
function slugExists(slug: string): boolean {
  // 檢查 wiki/queries/ 目錄
  if (existsSync(path.join(WIKI_QUERIES_DIR, `${slug}.md`))) return true;

  // 檢查候選 log 中是否已有此 slug
  if (!existsSync(CANDIDATES_PATH)) return false;
  try {
    const content = readFileSync(CANDIDATES_PATH, "utf8");
    return content.includes(`"slug":"${slug}"`);
  } catch { return false; }
}

// ─── 公開 API ─────────────────────────────────────────────────────────────

/**
 * 評估一個回覆是否值得自動存入 wiki。
 * 呼叫時機：run-prompt 完成後、非 meta 模式、agent 未自行加 WIKI_QUERY token。
 *
 * @param question - 使用者原始問題
 * @param reply - agent 完整回覆文字
 * @returns 評估結果
 */
export function evaluateForAutoSave(question: string, reply: string): AutoSaveEvalResult {
  const result: AutoSaveEvalResult = {
    shouldSave: false,
    slug: null,
    summary: null,
    matchedTopics: [],
    skipReason: null,
  };

  // 條件 1：長度門檻
  if (reply.length < MIN_REPLY_LENGTH) {
    result.skipReason = `回覆太短（${reply.length} < ${MIN_REPLY_LENGTH}）`;
    return result;
  }

  // 條件 2：topic 多樣性
  const topicNames = loadTopicNames();
  const matched = detectTopics(reply, topicNames);
  result.matchedTopics = matched;

  if (matched.length < MIN_TOPIC_DIVERSITY) {
    result.skipReason = `topic 多樣性不足（${matched.length} < ${MIN_TOPIC_DIVERSITY}）`;
    return result;
  }

  // 產出 slug 和 summary
  const slug = generateSlug(question);
  const summary = generateSummary(question, reply);

  // 條件 3：dedup
  if (slugExists(slug)) {
    result.skipReason = `slug "${slug}" 已存在`;
    return result;
  }

  result.shouldSave = true;
  result.slug = slug;
  result.summary = summary;
  return result;
}

/**
 * 把一個通過評估的候選寫入候選 log。
 * 呼叫端可決定是否同時觸發 meta prompt（即時寫 wiki page）。
 */
export function recordAutoSaveCandidate(
  question: string,
  reply: string,
  evalResult: AutoSaveEvalResult,
): AutoSaveCandidate | null {
  if (!evalResult.shouldSave || !evalResult.slug || !evalResult.summary) return null;

  const candidate: AutoSaveCandidate = {
    ts: new Date().toISOString(),
    slug: evalResult.slug,
    summary: evalResult.summary,
    matchedTopics: evalResult.matchedTopics,
    replyLength: reply.length,
    questionPreview: question.slice(0, 100),
    processed: false,
  };

  try {
    const dir = path.dirname(CANDIDATES_PATH);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    appendFileSync(CANDIDATES_PATH, JSON.stringify(candidate) + "\n", "utf8");

    // 體積控制
    trimCandidates();
  } catch (err) {
    console.error("[query-auto-save] failed to record candidate:", err);
    return null;
  }

  return candidate;
}

/**
 * 取得未處理的候選清單（供 /dream wikisync 消費）。
 */
export function getPendingCandidates(): AutoSaveCandidate[] {
  if (!existsSync(CANDIDATES_PATH)) return [];

  try {
    const content = readFileSync(CANDIDATES_PATH, "utf8");
    const lines = content.trim().split("\n").filter(Boolean);
    const candidates: AutoSaveCandidate[] = [];

    for (const line of lines) {
      try {
        const c: AutoSaveCandidate = JSON.parse(line);
        if (!c.processed) candidates.push(c);
      } catch { /* 跳過 */ }
    }

    return candidates;
  } catch { return []; }
}

/**
 * 標記候選為已處理（wikisync 完成後呼叫）。
 * @param slugs - 已處理的 slug 列表
 */
export function markCandidatesProcessed(slugs: string[]): void {
  if (!existsSync(CANDIDATES_PATH)) return;

  try {
    const content = readFileSync(CANDIDATES_PATH, "utf8");
    const lines = content.trim().split("\n").filter(Boolean);
    const slugSet = new Set(slugs);

    const updated = lines.map((line) => {
      try {
        const c: AutoSaveCandidate = JSON.parse(line);
        if (slugSet.has(c.slug)) c.processed = true;
        return JSON.stringify(c);
      } catch { return line; }
    });

    writeFileSync(CANDIDATES_PATH, updated.join("\n") + "\n", "utf8");
  } catch (err) {
    console.error("[query-auto-save] markCandidatesProcessed failed:", err);
  }
}

/** 體積控制：保留最新 MAX_CANDIDATES 筆 */
function trimCandidates(): void {
  try {
    const content = readFileSync(CANDIDATES_PATH, "utf8");
    const lines = content.trim().split("\n").filter(Boolean);
    if (lines.length <= MAX_CANDIDATES) return;

    const trimmed = lines.slice(-MAX_CANDIDATES);
    writeFileSync(CANDIDATES_PATH, trimmed.join("\n") + "\n", "utf8");
  } catch { /* 忽略 */ }
}

