/** Generate a 6-char hex hash for fact traceability. */
export function generateFactId(text: string): string {
  return createHash("sha256").update(text.trim()).digest("hex").slice(0, 6);
}

export function formatFactLine(text: string, ts?: string): string {
  const t = (ts ?? new Date().toISOString()).trim();
  const id = generateFactId(text);
  return `- [f_${id}] [${t}] ${text.trim()}\n`;
}

