/**
 * Load rules from disk, cache briefly, fall back to defaults on any
 * error. Synchronous on purpose — callers are hot paths (preamble build,
 * MCP tool invocation) and the file is tiny.
 */
export function getTopicRules(): TopicRule[] {
  const now = Date.now();
  if (cached && now - cached.loadedAt < CACHE_TTL_MS) return cached.rules;

  const file = resolveTopicsFile();
  let rules: TopicRule[] = DEFAULT_TOPIC_RULES;
  let source = "built-in defaults";

  if (existsSync(file)) {
    try {
      const raw = readFileSync(file, "utf8");
      // Strip JSONC-style line comments (// ...) so the generated header
      // comments in topics.json don't trip JSON.parse. We keep it simple:
      // only full-line // comments are stripped, not inline ones, to avoid
      // accidentally eating // inside keyword strings.
      const stripped = raw
        .split(/\r?\n/)
        .filter((l) => !/^\s*\/\//.test(l))
        .join("\n");
      const parsed = JSON.parse(stripped);
      const validated = validateRules(parsed, file);
      if (validated) {
        rules = validated;
        source = file;
      } else {
        console.warn(`[topic-rules] ${file}: validation failed, using built-in defaults`);
      }
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      console.warn(`[topic-rules] ${file}: read/parse failed (${msg}), using built-in defaults`);
    }
  }

  cached = { rules, loadedAt: now, source };
  return rules;
}

/**
 * Force the next getTopicRules() call to re-read from disk. Exposed for
 * tests and for a future `/retopic` command that edits topics.json at
 * runtime.
 */
export function invalidateTopicRulesCache(): void {
  cached = null;
}

/** Diagnostic helper — tells you which file (or "built-in") is active. */
export function topicRulesSource(): string {
  if (!cached) getTopicRules();
  return cached?.source ?? "built-in defaults";
}

