/**
 * Validate a parsed JSON blob against the TopicRule[] shape. Returns
 * `null` + logs a warning if the shape is wrong; never throws. Duplicate
 * topic names are deduped keeping the first occurrence.
 */
function validateRules(data: unknown, source: string): TopicRule[] | null {
  if (!Array.isArray(data)) {
    console.warn(`[topic-rules] ${source}: expected JSON array, got ${typeof data}`);
    return null;
  }
  const seen = new Set<string>();
  const out: TopicRule[] = [];
  for (let i = 0; i < data.length; i++) {
    const row = data[i] as unknown;
    if (!row || typeof row !== "object") {
      console.warn(`[topic-rules] ${source}: entry #${i} is not an object, skipped`);
      continue;
    }
    const { topic, keywords } = row as { topic?: unknown; keywords?: unknown };
    if (typeof topic !== "string" || topic.trim() === "") {
      console.warn(`[topic-rules] ${source}: entry #${i} missing string 'topic', skipped`);
      continue;
    }
    if (!Array.isArray(keywords) || keywords.some((k) => typeof k !== "string")) {
      console.warn(`[topic-rules] ${source}: entry #${i} ('${topic}') missing string[] 'keywords', skipped`);
      continue;
    }
    const topicName = topic.trim();
    if (seen.has(topicName.toLowerCase())) {
      console.warn(`[topic-rules] ${source}: duplicate topic '${topicName}' skipped`);
      continue;
    }
    seen.add(topicName.toLowerCase());
    const kws = (keywords as string[])
      .map((k) => k.trim())
      .filter((k) => k.length > 0);
    if (kws.length === 0) {
      console.warn(`[topic-rules] ${source}: topic '${topicName}' has no keywords, skipped`);
      continue;
    }
    out.push({ topic: topicName, keywords: kws });

