// Local smoke test: verifies topic-rules helpers, the OR-match that used
// to live in mcp-memory.ts listFacts, and the new shard fast-path.
// Run from project root (需帶 --env-file 載入 MEMORY_DIR，否則 fallback F:\AI\AIMemory)：
//   node --env-file=.env scripts/check-topic-match.mjs
//
// Exits non-zero if shard vs OR-scan counts disagree — that would mean
// facts_Topic/<uid>/ is out of sync with the master log and rebuild is
// needed.
//
// userId 偵測順序：env MEMORY_USER_ID → MEMORY_DIR/.user-id → glob facts-*.md
import { readFile } from "node:fs/promises";
import { existsSync, readFileSync, readdirSync } from "node:fs";
import path from "node:path";
import {
  keywordsForTopic,
  classifyFact,
  topicKeywordHint,
} from "../dist/topic-rules.js";
import {
  readTopicFacts,
  listTopicShards,
  userShardDir,
} from "../dist/facts-store.js";

// 動態取得 MEMORY_DIR（與 config.ts 相同邏輯）
const MEMORY_DIR = process.env.MEMORY_DIR?.trim() || "F:\\AI\\AIMemory";

// 動態偵測 userId
function detectUserId(memoryDir) {
  // 1. env
  if (process.env.MEMORY_USER_ID) return Number(process.env.MEMORY_USER_ID);
  // 2. .user-id 檔案
  const userIdFile = path.join(memoryDir, ".user-id");
  if (existsSync(userIdFile)) {
    const content = readFileSync(userIdFile, "utf8").trim();
    if (/^\d+$/.test(content)) return Number(content);
  }
  // 3. glob facts-*.md
  const entries = readdirSync(memoryDir);
  for (const e of entries) {
    const m = e.match(/^facts-(\d+)\.md$/);
    if (m) return Number(m[1]);
  }
  throw new Error(
    `Cannot detect userId. Set MEMORY_USER_ID env or create ${userIdFile}`
  );
}

const userId = detectUserId(MEMORY_DIR);

