  `回覆末尾加上：<<SKILL_USED:ms-wiki-knowledge-base|wikisync 步驟>>`;

/**
 * 組出這一輪 wikisync 的完整 prompt：基底 WIKISYNC_PROMPT + Ingest Ripple
 * 優先清單 + Query Auto-save 候選。回傳注入的 topic/slug 清單，供完成後
 * 樂觀清理（部分失敗會由下次 ripple 累積重新標記）。
 */
function buildWikiSyncPrompt(): { prompt: string; rippleTopics: string[]; candidateSlugs: string[] } {
  let prompt = WIKISYNC_PROMPT;
  const rippleTopics: string[] = [];
  const candidateSlugs: string[] = [];

  try {
    const ripple = getRippleStatus();
    const top = ripple.pagesNeedingUpdate.slice(0, 5);
    if (top.length) {
      rippleTopics.push(...top.map((p) => p.topic));
      prompt +=
        `\n\n【Ingest Ripple 優先清單】以下 wiki page 自上次同步後已累積新 facts，步驟 4 請優先處理：\n` +
        top.map((p) => `- wiki/${p.type}/${p.slug}.md（topic: ${p.topic}，${p.pendingCount} 條未同步）`).join("\n");
    }
  } catch (err) {
    console.warn("[wikisync] ripple status read failed:", err);
  }

  try {
    const candidates = getPendingCandidates().slice(0, 5);
    if (candidates.length) {
      candidateSlugs.push(...candidates.map((c) => c.slug));
      prompt +=
        `\n\n【Query Auto-save 候選】以下回覆被自動判定值得存為 query page，` +
        `請各產出一頁 wiki/queries/<slug>.md（frontmatter type: query，規則同上）：\n` +
        candidates.map((c) => `- ${c.slug} — ${c.summary}`).join("\n");
    }
  } catch (err) {
    console.warn("[wikisync] auto-save candidates read failed:", err);
  }

  return { prompt, rippleTopics, candidateSlugs };
}

export async function handleWikiSync(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`,
    );
    return;
  }
  const { prompt, rippleTopics, candidateSlugs } = buildWikiSyncPrompt();
  await runPrompt(ctx, session, prompt, { kind: "meta" });
  // 樂觀清理：這輪已把清單交給 agent 處理，清掉標記避免下輪重複注入。
  // 若 agent 部分失敗，後續新 fact 寫入會重新累積 ripple 標記。
  if (rippleTopics.length) clearProcessedRipples(rippleTopics);
  if (candidateSlugs.length) markCandidatesProcessed(candidateSlugs);
}

