117	        structuredResult = result as import("../dream-config.js").DreamStepResult;
118	        summary = structuredResult.summary;
119	      } else if (session && session.buffer !== bufferBefore) {
120	        // Agent produced output — use last buffer content directly (truncated)
121	        // This is the agent's actual work output, much better than asking it to summarize itself
122	        const rawOutput = session.buffer.trim();
123	        summary = rawOutput.slice(0, 400) || "(no output)";
124	      } else {
125	        summary = "(no output)";
126	      }
127	
128	      stepResults.push({ cmd: step.cmd, ok: true, summary, result: structuredResult });
129	    } catch (err) {
130	      const msg = (err as Error).message;
131	      await ctx.reply(
132	        `⚠ Step ${i + 1}/${runnable.length} /${step.cmd} 失敗：${msg}`,
133	      );
134	      stepResults.push({ cmd: step.cmd, ok: false, summary: msg });
135	      if (!cfg.continue_on_error) {
136	        await ctx.reply(
137	          `🛑 continue_on_error=false，中斷剩餘 ${runnable.length - i - 1} 步。`,
138	        );
139	        break;
140	      }
141	    }
142	  }
143	
144	  // Generate final dream summary report
145	  try {
146	    let dreamReport = "📋 Dream 綜合報告\n━━━━━━━━━━━━━━━━━━━\n";
147	    const allActionItems: string[] = [];
148	
149	    for (const r of stepResults) {
150	      const icon = r.ok ? "✅" : "❌";
151	      // Use structured result's summary if available, else use captured buffer summary
152	      const displaySummary = r.result?.summary ?? r.summary.slice(0, 200);
153	      dreamReport += `${icon} /${r.cmd}：${displaySummary}\n`;
154	
155	      // Collect action items from structured results
156	      if (r.result?.actionItems) {
157	        allActionItems.push(...r.result.actionItems.map(a => `[/${r.cmd}] ${a}`));
158	      }
159	    }
160	
161	    // If we have structured action items, list them directly (no LLM needed)
162	    if (allActionItems.length > 0) {
163	      dreamReport += `\n🎯 需要處理的項目（${allActionItems.length}）：\n`;
164	      dreamReport += allActionItems.map((a, i) => `${i + 1}. ${a}`).join("\n");
165	    }
166	
167	    // Only ask LLM for suggestions if there are agent-based steps with substantial output
168	    // and no structured action items already cover the situation
169	    const agentSteps = stepResults.filter(r => r.ok && !r.result && r.summary.length > 50);
170	    if (session && agentSteps.length > 0) {
171	      const stepsText = agentSteps
172	        .map(r => `/${r.cmd}：${r.summary.slice(0, 300)}`)
173	        .join("\n");
174	      await runPrompt(ctx, session,
175	        `以下是 dream routine 各 agent 步驟的直接輸出摘要：\n${stepsText}\n\n` +
176	        `請只列出「需要人工處理」的項目（如果有的話），格式：\n` +
177	        `每項一行「- [emoji] 具體描述（來源：/步驟名）」\n` +
178	        `emoji：🔺升格 ⚠️矛盾 ✂️拆分 🗑️清理 📝更新 🐛問題\n` +
179	        `如果沒有需要人工處理的就回「✨ 系統健康，無需額外動作。」\n` +
180	        `不要重複上面已列出的內容。精簡回答，不要解釋。`,
181	        { kind: "meta", silent: true },
182	      );
183	      const actionText = (session.buffer || "").trim();
184	      if (actionText && !actionText.includes("無需額外動作")) {
185	        dreamReport += `\n\n🤖 建議：\n${actionText}`;
186	      }
187	    }
188	
189	    if (allActionItems.length === 0 && !dreamReport.includes("建議")) {
190	      dreamReport += "\n\n✨ 系統健康，無需額外動作。";
191	    }
192	
193	    try {
194	      await ctx.reply(dreamReport);
195	    } catch {
196	      await ctx.reply(dreamReport.replace(/\*\*/g, "").replace(/━+/g, "---"));
197	    }
198	    await ctx.reply(`✅ Dream routine 完成（${stepResults.filter(r => r.ok).length}/${runnable.length}）。`);
199	  } catch (reportErr) {
200	    console.error("[dream] report generation failed:", reportErr);
201	    await ctx.reply(`✅ Dream routine 完成（報告產出失敗：${(reportErr as Error).message}）`).catch(() => {});
202	  }
203	
204	  // ── Write STATE.md (three-tier loop state) ──
205	  try {
206	    if (session && stepResults.length > 0) {
207	      const statePrompt =
208	        `以下是今天 dream routine 各步驟結果：\n` +
209	        stepResults.map(r => `${r.ok ? "✅" : "❌"} /${r.cmd}：${r.summary}`).join("\n") +
210	        `\n\n請根據上述結果，產出三段式 Loop State。格式嚴格如下（直接輸出 Markdown，不要包在 code block）：\n\n` +
211	        `# Loop State — telegram-kiro-bridge\n` +
212	        `Last run: ${new Date().toISOString()}\n\n` +
213	        `## High Priority (action needed)\n` +
214	        `- （需要人工介入的項目：矛盾待確認、失敗步驟、skill orphan、膨脹警告等）\n\n` +
215	        `## Watch List (monitor)\n` +
216	        `- （值得關注但不急的：沉默 topic、wiki 過期、pending 升格候選等）\n\n` +
217	        `## Noise (ignored this run)\n` +
218	        `- （正常完成、無需關注的：backup 成功、artifact 清理等）\n\n` +
219	        `規則：\n` +
220	        `- 每段只列有內容的項目（1 行 1 項，dash list）\n` +
221	        `- 失敗步驟一律進 High Priority\n` +
222	        `- 某段沒東西就寫「— 無」\n` +
223	        `- 全文 ≤30 行\n` +
224	        `- 不要加任何額外說明`;
225	      await runPrompt(ctx, session, statePrompt, { kind: "meta", silent: true });
226	      const stateContent = (session.buffer || "").trim();
227	      if (stateContent && stateContent.includes("## High Priority")) {
228	        const statePath = path.join(MEMORY_DIR, "STATE.md");
229	        writeFileSync(statePath, stateContent + "\n", "utf8");
230	      }
231	    }
232	  } catch (stateErr) {
233	    console.error("[dream] STATE.md write failed:", stateErr);
234	  }
235	
236	  // Daily event log rotation
237	  try {
238	    const { deleted, kept } = rotateEventLog();
239	    if (deleted > 0) {
