325	
326	export async function handleArtifactCleanup(ctx: Context): Promise<import("../dream-config.js").DreamStepResult | void> {
327	  const { isAllowed } = deps();
328	  if (!isAllowed(ctx)) return;
329	  const dir = path.join(config.memoryDir, "artifacts");
330	  let deleted = 0;
331	  let remaining = 0;
332	  try {
333	    const files = await readdir(dir).catch(() => [] as string[]);
334	    const cutoff = Date.now() - 7 * 24 * 60 * 60 * 1000;
335	    for (const f of files) {
336	      if (!f.endsWith(".json")) continue;
337	      const dateStr = f.slice(0, 10);
338	      const ts = new Date(dateStr).getTime();
339	      if (!isNaN(ts) && ts < cutoff) {
340	        await unlink(path.join(dir, f));
341	        deleted++;
342	      }
343	    }
344	    remaining = files.length - deleted;
345	    await ctx.reply(`🧹 Artifact cleanup：刪除 ${deleted} 個超過 7 天的檔案（剩餘 ${remaining} 個）`);
346	  } catch (err: any) {
347	    await ctx.reply(`❌ artifact cleanup 失敗：${err.message}`);
348	    return;
349	  }
350	
351	  // Stale index report
352	  const staleIndexes: string[] = [];
353	  try {
354	    const stale = findStaleIndexes(MEMORY_DIR, 30);
355	    if (stale.length > 0) {
356	      staleIndexes.push(...stale.map((s) => `${s.slug}: ${s.title} (created ${s.created_at.slice(0, 10)})`));
357	      const lines = stale.map((s) => `  - ${s.slug}: ${s.title} (created ${s.created_at.slice(0, 10)})`);
358	      await ctx.reply(`📚 Stale indexes（>30天未查詢，建議清理）：\n${lines.join("\n")}`);
359	    }
360	  } catch { /* non-critical */ }
361	
362	  return {
363	    summary: `刪除 ${deleted} 個舊 artifact，剩餘 ${remaining} 個${staleIndexes.length ? `；${staleIndexes.length} 個 stale index` : ""}`,
364	    metrics: { deleted, remaining, staleIndexes: staleIndexes.length },
365	    actionItems: staleIndexes.length > 0 ? staleIndexes.map(s => `清理 stale index: ${s}`) : undefined,
366	  };
367	}
