407	export async function handleUtilityReport(ctx: Context): Promise<void> {
408	  const { isAllowed } = deps();
409	  if (!isAllowed(ctx)) return;
410	  const userId = ctx.from?.id;
411	  if (!userId) return;
412	
413	  try {
414	    const stats = await getHitStats(7);
415	    const shardInfos = listTopicShards(userId);
416	
417	    const active: string[] = [];
418	    const silentFacts: string[] = [];
419	    const silentWiki: string[] = [];
420	
421	    for (const s of shardInfos) {
422	      const count = stats.get(`fact:${s.topic}`) ?? 0;
423	      if (count >= 3) active.push(`fact:${s.topic} (${count})`);
424	      else if (count === 0) silentFacts.push(s.topic);
425	    }
426	    for (const [k, v] of stats) {
427	      if (k.startsWith("wiki:") && v >= 3) active.push(`${k} (${v})`);
428	      if (k.startsWith("skill:") && v >= 3) active.push(`${k} (${v})`);
429	    }
430	    try {
431	      const indexRaw = readFileSync(path.join(config.memoryDir, "wiki", "index.md"), "utf8");
432	      const slugs = [...indexRaw.matchAll(/\[\[([^\]]+)\]\]/g)].map(m => m[1]);
433	      for (const slug of slugs) {
434	        if (!stats.has(`wiki:${slug}`)) silentWiki.push(slug);
435	      }
436	    } catch { /* no wiki index */ }
437	
438	    let report = "📊 **效用報告（過去 7 天）**\n\n";
439	    if (active.length > 0) {
440	      report += `✅ 活躍（≥3 次命中）：\n${active.slice(0, 15).map(a => `  ${a}`).join("\n")}\n\n`;
441	    }
442	    const silentTotal = silentFacts.length + silentWiki.length;
443	    if (silentTotal > 0) {
444	      report += `💤 沉默（0 次命中）：\n`;
445	      if (silentFacts.length) report += `  Facts: ${silentFacts.slice(0, 10).join(", ")}${silentFacts.length > 10 ? ` (+${silentFacts.length - 10})` : ""}\n`;
446	      if (silentWiki.length) report += `  Wiki: ${silentWiki.slice(0, 10).join(", ")}${silentWiki.length > 10 ? ` (+${silentWiki.length - 10})` : ""}\n`;
447	    }
448	    if (silentTotal === 0 && active.length === 0) {
449	      report += "（hit-log 尚無資料，需累積幾天使用後再看）";
450	    }
451	
452	    // Tool usage heatmap (from tool_call events in event-log)
453	    try {
454	      const tool = getToolUsageStats(7);
455	      if (tool.total > 0) {
456	        const top = tool.byTool.slice(0, 10).map(t => {
457	          const failNote = t.failed > 0 ? ` ⚠️${t.failed} 失敗` : "";
458	          return `  ${t.name}: ${t.total}${failNote}`;
459	        });
460	        const failRate = Math.round((tool.failed / tool.total) * 100);
461	        report += `\n\n🔧 工具使用（過去 7 天，共 ${tool.total} 次，失敗率 ${failRate}%）：\n${top.join("\n")}`;
462	        if (tool.byTool.length > 10) report += `\n  …另有 ${tool.byTool.length - 10} 種工具`;
463	      }
464	    } catch { /* event-log unavailable — skip tool stats */ }
465	
466	    // Optional LLM annotation for silent items
467	    if (silentTotal > 0) {
468	      try {
469	        const { detectLlamaCpp, localComplete } = await import("../local-llm.js");
470	        if (await detectLlamaCpp()) {
471	          const sample = [...silentFacts.slice(0, 3), ...silentWiki.slice(0, 3)].join(", ");
472	          const raw = await localComplete(
473	            `These memory topics/wiki pages had 0 hits in 7 days: ${sample}\n` +
474	            `For each, give ONE reason (10 words max): "bad description", "topic obsolete", or "just not encountered recently".\n` +
475	            `Format: name: reason`,
476	            { maxTokens: 150, timeout: 15000 },
477	          );
478	          if (raw) report += `\n🔍 沉默原因（LLM 判斷）：\n${raw}\n`;
479	        }
480	      } catch { /* Ollama unavailable — skip annotation */ }
481	    }
482	
483	    // Tool usage heatmap (from tool_call events in event-log)
484	    try {
485	      const tool = getToolUsageStats(7);
486	      if (tool.total > 0) {
487	        const top = tool.byTool.slice(0, 10).map(t => {
488	          const failNote = t.failed > 0 ? ` (❌${t.failed} fail)` : "";
489	          return `  ${t.name}: ${t.total}${failNote}`;
490	        });
491	        const failRate = Math.round((tool.failed / tool.total) * 100);
492	        report += `\n\n🔧 **工具使用（7 天 / ${tool.total} 次 / 失敗率 ${failRate}%）**\n${top.join("\n")}`;
493	        if (tool.byTool.length > 10) report += `\n  …+${tool.byTool.length - 10} 其他工具`;
494	      }
495	    } catch { /* event-log unavailable — skip tool stats */ }
496	
497	    await ctx.reply(report, { parse_mode: "Markdown" });
498	  } catch (err: any) {
499	    await ctx.reply(`❌ utility report 失敗：${err.message}`);
500	  }
501	}
