506	export async function handleSharedPull(ctx: Context): Promise<void> {
507	  const { isAllowed } = deps();
508	  if (!isAllowed(ctx)) return;
509	  const sharedDir = path.join(config.memoryDir, "shared");
510	  try {
511	    const { execFileSync } = await import("node:child_process");
512	    const git = (args: string[], timeout = 5000) =>
513	      execFileSync("git", args, { cwd: sharedDir, encoding: "utf8", timeout }).trim();
514	    const before = git(["rev-parse", "HEAD"]);
515	    const out = git(["pull", "--ff-only"], 30000);
516	    const after = git(["rev-parse", "HEAD"]);
517	
518	    let newFiles: string[] = [];
519	    if (before !== after) {
520	      const diff = git(["diff", "--name-only", before, after]);
521	      if (diff) {
522	        newFiles = [...new Set(diff.split(/\r?\n/))]
523	          .map((f) => f.replace(/\\/g, "/").trim())
524	          .filter((f) => f.endsWith(".md") && f !== "README.md")
525	          .sort();
526	      }
527	    }
528	
529	    let msg = `📥 Shared pull：${out || "Already up to date."}`;
530	    if (newFiles.length > 0) {
531	      msg += `\n\n📄 新/更新頁面（${newFiles.length}）：\n${newFiles.map((f) => `  - ${f}`).join("\n")}`;
532	      msg += `\n\n💡 接著會請 agent 讀取上述頁面，判斷是否值得內化為本機 memory/wiki。`;
533	    }
534	    await ctx.reply(msg);
535	    await triggerSharedReview(ctx, sharedDir, newFiles);
536	  } catch (err: any) {
537	    await ctx.reply(`⚠️ shared-pull 失敗：${err.message?.slice(0, 200)}`);
538	  }
539	}
