// Local smoke test: verifies the Karpathy Wiki P0 trio end-to-end at the
// module level — query-auto-save (JSONC topics.json 解析 + 門檻判斷 + dedup +
// 候選 log)、ingest-ripple (pendingCount / threshold / 清理)、activity-log
// (統一活動流聚合)。
//
// 全程使用隔離 temp MEMORY_DIR，不讀不寫真實記憶體資料。直接跑：
//   node scripts/check-wiki-autosave.mjs
//
// 需先 build（scripts 吃 dist/）：tsc -p .
import { mkdtempSync, mkdirSync, writeFileSync, rmSync, existsSync, readFileSync } from "node:fs";
import { tmpdir } from "node:os";
import path from "node:path";

// ─── 隔離環境：必須在 import dist 模組前設好 ─────────────────────────────
const MEM = mkdtempSync(path.join(tmpdir(), "check-wiki-autosave-"));
process.env.MEMORY_DIR = MEM;
process.env.MEMORY_USER_ID = "12345";

const UID = "12345";
const now = new Date().toISOString();

// topics.json — 帶 JSONC 標頭註解（/topic-review 產出的真實格式）
writeFileSync(path.join(MEM, "topics.json"),
  `// Auto-generated by /topic-review — do not edit the header\n` +
  `// schema: [{ topic, keywords }]\n` +
  `[\n` +
  `  { "topic": "bridge-relay", "keywords": ["relay", "橋接"] },\n` +
  `  { "topic": "memory-sync", "keywords": ["memory", "記憶同步"] },\n` +
  `  { "topic": "wiki-pages", "keywords": ["wiki"] },\n` +
  `  { "topic": "unrelated-topic", "keywords": ["zzznomatch"] }\n` +
  `]\n`, "utf8");

// wiki/index.md + concepts page（sources 已追蹤 1 個 fact）
mkdirSync(path.join(MEM, "wiki", "concepts"), { recursive: true });
mkdirSync(path.join(MEM, "wiki", "queries"), { recursive: true });
writeFileSync(path.join(MEM, "wiki", "index.md"),
  `# Wiki Index\n\n## Pages\n- [[bridge-relay]] — relay 機制總覽\n`, "utf8");
writeFileSync(path.join(MEM, "wiki", "concepts", "bridge-relay.md"),
  `---\ntype: concept\nsources: [f_aaaaaa]\n---\n\nrelay 機制。\n`, "utf8");

// topic shard：4 條 facts（1 條已被 sources 追蹤 → pending 應為 3）
mkdirSync(path.join(MEM, "facts_Topic", UID), { recursive: true });
writeFileSync(path.join(MEM, "facts_Topic", UID, "bridge-relay.md"),
  `- [f_aaaaaa] [${now}] relay fact 1\n` +
  `- [f_bbbbbb] [${now}] relay fact 2\n` +
  `- [f_cccccc] [${now}] relay fact 3\n` +
  `- [f_dddddd] [${now}] relay fact 4\n`, "utf8");

// 活動流三來源
writeFileSync(path.join(MEM, "hit-log.jsonl"),
  JSON.stringify({ ts: now, type: "fact", key: "bridge-relay", source: "preamble" }) + "\n" +
  JSON.stringify({ ts: now, type: "wiki", key: "bridge-relay", source: "retrieval" }) + "\n", "utf8");
writeFileSync(path.join(MEM, "events.jsonl"),
  JSON.stringify({ ts: now, type: "session_start", payload: { sessionId: "abcdef12345" } }) + "\n", "utf8");

// ─── 載入 dist 模組（MEMORY_DIR 已生效） ─────────────────────────────────
const { evaluateForAutoSave, recordAutoSaveCandidate, getPendingCandidates, markCandidatesProcessed } =
  await import("../dist/query-auto-save.js");
const { onFactIngested, getRippleStatus, clearProcessedRipples } =
  await import("../dist/ingest-ripple.js");
const { queryActivity, getActivitySummary } =
  await import("../dist/activity-log.js");

let failed = 0;
function check(name, cond, detail = "") {
  if (cond) { console.log(`  ✅ ${name}`); }
  else { console.error(`  ❌ ${name}${detail ? ` — ${detail}` : ""}`); failed++; }
}

// ─── 1. query-auto-save ──────────────────────────────────────────────────
console.log("[1] query-auto-save");
const question = "how to configure bridge relay and memory sync";
const pad = "測試".repeat(80); // 160 字 padding，不含任何 keyword
const goodReply = `這輪回覆講 relay 橋接、memory 記憶同步、還有 wiki 頁面的關係。${pad}`;

const evalGood = evaluateForAutoSave(question, goodReply);
check("長回覆 + ≥3 topics → shouldSave", evalGood.shouldSave === true, evalGood.skipReason ?? "");
check("matchedTopics ≥ 3", evalGood.matchedTopics.length >= 3, JSON.stringify(evalGood.matchedTopics));
check("slug 產出", typeof evalGood.slug === "string" && evalGood.slug.length >= 3, String(evalGood.slug));

const evalShort = evaluateForAutoSave(question, "短回覆 relay memory wiki");
check("短回覆 → skip", evalShort.shouldSave === false && /太短/.test(evalShort.skipReason ?? ""));

const evalNarrow = evaluateForAutoSave(question, `只講 relay 的內容。${pad}`);
check("topic 多樣性不足 → skip", evalNarrow.shouldSave === false && /多樣性/.test(evalNarrow.skipReason ?? ""));

const rec = recordAutoSaveCandidate(question, goodReply, evalGood);
check("候選寫入", rec !== null && existsSync(path.join(MEM, "wiki", "wiki-auto-save-candidates.jsonl")));
check("getPendingCandidates = 1", getPendingCandidates().length === 1);

const evalDup = evaluateForAutoSave(question, goodReply);
check("同 slug dedup → skip", evalDup.shouldSave === false && /已存在/.test(evalDup.skipReason ?? ""));

markCandidatesProcessed([evalGood.slug]);
check("markCandidatesProcessed 後 pending = 0", getPendingCandidates().length === 0);

// ─── 2. ingest-ripple ────────────────────────────────────────────────────
console.log("[2] ingest-ripple");
onFactIngested("bridge-relay", "新的 relay fact", "f_dddddd");
const ripple1 = getRippleStatus();
check("有 wiki page 的 topic 進入狀態", ripple1.pagesNeedingUpdate.length + ripple1.pagesWatching.length === 1,
  JSON.stringify(ripple1));
check("pendingCount = 3（4 shard facts − 1 已追蹤）",
