// Smoke: verify the bridge pins ACP model / effort via session/set_config_option.
//
// Spawns the ACP agent (default: ACP_AGENT_COMMAND, else "claude-agent-acp"),
// runs the bridge handshake with acpModel/acpEffort set, and checks that the
// adapter accepted each option — detected by the "[acp] pinned <id>=<value>"
// stderr line AcpClient.applyModelEffort emits on success. A "not applied"
// line (unknown method / invalid value / dead stream) fails the check and
// prints the adapter's reason.
//
// Run (uses .env's ACP_AGENT_COMMAND — must be a Claude adapter):
//   node scripts/check-acp-model-effort.mjs
//   node scripts/check-acp-model-effort.mjs --model claude-fable-5 --effort medium
//   node scripts/check-acp-model-effort.mjs claude-agent-acp --model fable-5
//
// Uses compiled dist/acpClient.js — run `npx tsc` first.
//
// Exit codes: 0 = both requested options pinned; 1 = failure/rejection; 2 = bad usage.

import "dotenv/config";
import { AcpClient } from "../dist/acpClient.js";

function parseArgs(argv) {
  let model = "claude-fable-5";
  let effort = "medium";
  let timeoutMs = 30_000;
  const rest = [];
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === "--model") { model = argv[++i]; }
    else if (a === "--effort") { effort = argv[++i]; }
    else if (a === "--timeout" || a === "-t") { timeoutMs = Number(argv[++i]); }
    else rest.push(a);
  }
  if (!Number.isFinite(timeoutMs) || timeoutMs <= 0) {
    console.error("error: --timeout expects a positive number");
    process.exit(2);
  }
  // Command: explicit argv wins, else fall back to the bridge's .env value.
  let command, args;
  if (rest.length > 0) {
    command = rest[0];
    args = rest.slice(1);
  } else {
    const raw = (process.env.ACP_AGENT_COMMAND ?? "claude-agent-acp").trim().split(/\s+/);
    command = raw[0];
    args = raw.slice(1);
  }
  return { command, args, model, effort, timeoutMs };
}

