// ─── handleRestart ────────────────────────────────────────────────────────────

export async function handleRestart(
  ctx: Context,
  opts: { reason?: string } = {},
): Promise<void> {
  const { bot, sessions, MEMORY_DIR, RESTART_PENDING_FILE,
    setRestartPendingChatId } = d();
  const isAllowed = (ctx: Context) => {
    const userId = ctx.from?.id;
    return userId !== undefined && config.allowedUserIds.includes(userId);
  };
  if (!isAllowed(ctx)) return;
  const reason = opts.reason?.trim() || "";
  const replyText = reason
    ? `🔄 Agent requested restart: ${reason}\nRestarting bridge… (extracting facts first)`
    : "Restarting bridge… (extracting facts first)";
  await ctx.reply(replyText);
